const grpc = require('@grpc/grpc-js');
const protoLoader = require('@grpc/proto-loader');
const express = require('express');

class GrpcClient {
  constructor(protoPath, packageName, serviceName, serverAddress) {
    const packageDefinition = protoLoader.loadSync(protoPath, {
      keepCase: true,
      longs: String,
      enums: String,
      defaults: true,
      oneofs: true
    });
    
    const protoDescriptor = grpc.loadPackageDefinition(packageDefinition);
    const servicePackage = packageName.split('.').reduce((obj, key) => obj[key], protoDescriptor);
    
    this.client = new servicePackage[serviceName](
      serverAddress,
      grpc.credentials.createInsecure()
    );
  }

  createMetadataFromHeaders(headers, allowedHeaders = null) {
    const metadata = new grpc.Metadata();
    
    const defaultForwardHeaders = [
      'user-agent',
      'x-forwarded-for',
      'x-forwarded-host',
      'x-forwarded-proto',
      'x-real-ip',
      'x-request-id',
      'authorization',
      'content-type',
      'accept',
      'accept-language',
      'accept-encoding'
    ];

    const headersToForward = allowedHeaders || defaultForwardHeaders;

    Object.keys(headers).forEach(key => {
      const lowerKey = key.toLowerCase();
      
      if (headersToForward.includes(lowerKey) || lowerKey.startsWith('x-custom-')) {
        const value = headers[key];
        if (Array.isArray(value)) {
          value.forEach(v => metadata.add(lowerKey, v));
        } else {
          metadata.add(lowerKey, value);
        }
      }
    });

    return metadata;
  }

  call(method, request, headers, callback) {
    const metadata = this.createMetadataFromHeaders(headers);
    
    this.client[method](request, metadata, (error, response) => {
      if (error) {
        callback(error, null);
      } else {
        callback(null, response);
      }
    });
  }

  callWithCustomHeaders(method, request, headers, customHeadersList, callback) {
    const metadata = this.createMetadataFromHeaders(headers, customHeadersList);
    
    this.client[method](request, metadata, (error, response) => {
      if (error) {
        callback(error, null);
      } else {
        callback(null, response);
      }
    });
  }

  streamCall(method, request, headers) {
    const metadata = this.createMetadataFromHeaders(headers);
    return this.client[method](request, metadata);
  }
}

class HttpToGrpcGateway {
  constructor(grpcClient) {
    this.grpcClient = grpcClient;
    this.app = express();
    this.app.use(express.json());
  }

  setupRoute(httpMethod, path, grpcMethod, requestMapper, responseMapper) {
    this.app[httpMethod](path, (req, res) => {
      const grpcRequest = requestMapper ? requestMapper(req) : req.body;
      
      this.grpcClient.call(grpcMethod, grpcRequest, req.headers, (error, response) => {
        if (error) {
          const statusCode = this.grpcErrorToHttpStatus(error.code);
          res.status(statusCode).json({
            error: error.message,
            code: error.code
          });
        } else {
          const httpResponse = responseMapper ? responseMapper(response) : response;
          res.json(httpResponse);
        }
      });
    });
  }

  setupStreamRoute(httpMethod, path, grpcMethod, requestMapper) {
    this.app[httpMethod](path, (req, res) => {
      const grpcRequest = requestMapper ? requestMapper(req) : req.body;
      
      const stream = this.grpcClient.streamCall(grpcMethod, grpcRequest, req.headers);
      
      res.setHeader('Content-Type', 'application/json');
      res.setHeader('Transfer-Encoding', 'chunked');
      
      stream.on('data', (data) => {
        res.write(JSON.stringify(data) + '\n');
      });
      
      stream.on('error', (error) => {
        res.write(JSON.stringify({ error: error.message }) + '\n');
        res.end();
      });
      
      stream.on('end', () => {
        res.end();
      });
    });
  }

  grpcErrorToHttpStatus(grpcCode) {
    const statusMap = {
      [grpc.status.OK]: 200,
      [grpc.status.CANCELLED]: 499,
      [grpc.status.UNKNOWN]: 500,
      [grpc.status.INVALID_ARGUMENT]: 400,
      [grpc.status.DEADLINE_EXCEEDED]: 504,
      [grpc.status.NOT_FOUND]: 404,
      [grpc.status.ALREADY_EXISTS]: 409,
      [grpc.status.PERMISSION_DENIED]: 403,
      [grpc.status.RESOURCE_EXHAUSTED]: 429,
      [grpc.status.FAILED_PRECONDITION]: 400,
      [grpc.status.ABORTED]: 409,
      [grpc.status.OUT_OF_RANGE]: 400,
      [grpc.status.UNIMPLEMENTED]: 501,
      [grpc.status.INTERNAL]: 500,
      [grpc.status.UNAVAILABLE]: 503,
      [grpc.status.DATA_LOSS]: 500,
      [grpc.status.UNAUTHENTICATED]: 401
    };
    
    return statusMap[grpcCode] || 500;
  }

  listen(port, callback) {
    this.app.listen(port, callback);
  }
}

